    int n = nums.size();
    if (n == 0) {
        return {};
    }
    if (n == 1) {
        return nums;
    }

    // 1. Calculate max_left[i]: Maximum element in nums[0...i-1]
    std::vector<long long> max_left(n);
    // Since nums[i] >= 1, using 0 as a safe initial minimum sentinel value
